files.content:
php bin/mnb-scraper source:csv urls.csv --url-column=url --format=txt --output=storage/{{project_name}}/urls.txt
php bin/mnb-scraper bulk:crawl storage/{{project_name}}/urls.txt --profile=ecommerce --pipeline --job-dir=storage/{{project_name}}
php bin/mnb-scraper dataset:create storage/{{project_name}}/pipeline/records.json --id={{project_name}}
php bin/mnb-scraper eval:dataset {{project_name}} --format=json
